// All 120 exam questions in 3 blocks
const ALL_QUESTIONS = [
// ── BLOCK 1 (Q1-40) ──
{id:1,domain:"Data Model",q:"In ServiceNow CSM, which entity represents an individual person at a customer company in the B2B model?",opts:["Consumer","Account","Contact","User"],ans:2,exp:"In the B2B model, Contact represents the individual person at the customer company. Account is the company itself. Consumer is used in B2C model and is standalone — it does NOT belong to an Account."},
{id:2,domain:"Data Model",q:"Which system property controls whether ServiceNow CSM uses the B2B or B2C business model?",opts:["csm.enable.b2c","glide.cs.enable.b2b","cs.model.selector","csm.business.type"],ans:1,exp:"The property 'glide.cs.enable.b2b' controls the B2B/B2C model selection. When set to true, B2B (Account/Contact) mode is active. This is a CSM system property found under Customer Service > Administration > Properties."},
{id:3,domain:"Data Model",q:"What type of entitlement limits a customer to a specific NUMBER of cases per period?",opts:["Time-Based Entitlement","Service Entitlement","Product Entitlement","Allocated Entitlement"],ans:3,exp:"Allocated Entitlement defines a maximum number of cases (the allocation) for a contract period. Time-Based Entitlement is restricted by a time window (e.g., 20 hours per month), not a case count."},
{id:4,domain:"Data Model",q:"A consumer electronics company wants to support millions of individual end-users who have no company association. Which CSM data model should they implement?",opts:["B2B with Account and Contact","B2B with Consumer","B2C with Consumer as the primary entity","B2C with Contact linked to a consumer account"],ans:2,exp:"B2C model uses Consumer as the primary entity for individual end-users without company affiliations. B2B uses Account and Contact for business customers. The Consumer entity is standalone — it has no parent Account."},
{id:5,domain:"Data Model",q:"Which table in ServiceNow stores Install Base Items in CSM?",opts:["cmdb_ci","alm_asset","install_base_item","customer_install_base"],ans:2,exp:"Install Base Items are stored in the 'install_base_item' table. This is a CSM-specific table that tracks products actively deployed for a customer, linked to both the Product Model and the Account."},
{id:6,domain:"Data Model",q:"An entitlement is being set up for a customer who purchased 'Premium Support' that provides 24/7 access for 12 months regardless of how many cases they log. What type of entitlement is this?",opts:["Allocated Entitlement","Time-Based Entitlement","Service Entitlement","Product Entitlement"],ans:2,exp:"This is a Service Entitlement — it defines a service level (24/7 access) for a defined period (12 months) without limiting the number of cases. It's tied to a service offering rather than a product purchase or case count."},
{id:7,domain:"Data Model",q:"What happens during Entitlement Verification when a case is created for a customer without a valid entitlement?",opts:["The case creation is blocked automatically","A warning is displayed but agents can still proceed","The case is automatically escalated to a manager","The system creates a temporary entitlement"],ans:1,exp:"Entitlement Verification shows a warning when no valid entitlement is found, but agents CAN still proceed to create the case. The process does not block case creation — it provides visibility to agents."},
{id:8,domain:"Data Model",q:"Which entity links a specific product instance to a customer account, tracking that product as actively deployed?",opts:["Product Model","CMDB CI","Install Base Item","Asset Record"],ans:2,exp:"An Install Base Item represents a specific instance of a product (defined by a Product Model) that is actively deployed or activated for a customer Account. It is distinct from CMDB CIs, though integrations between them exist."},
{id:9,domain:"Configuration",q:"An implementer needs to create guided resolution paths for agents that auto-activate when a case reaches a certain state. Which tool creates these?",opts:["Flow Designer","Workflow Editor","Process Automation Designer (PAD)","Script Includes"],ans:2,exp:"Playbooks in CSM are created using Process Automation Designer (PAD). Not Flow Designer and not the classic Workflow Editor. PAD provides the lane-based, phase-driven playbook structure needed for CSM."},
{id:10,domain:"Configuration",q:"What is the primary purpose of the CSM-ITSM Bridge?",opts:["To share knowledge articles between CSM and ITSM","To allow creating an Incident from a Case when internal technical resolution is needed","To synchronize SLA definitions between modules","To enable agents to work in both ITSM and CSM simultaneously"],ans:1,exp:"The CSM-ITSM Bridge allows creating an ITSM Incident directly from a CSM Case when the issue requires internal IT resolution. The bridge is bidirectional — when the Incident closes, a Business Rule automatically updates the linked Case."},
{id:11,domain:"Configuration",q:"In CSM AWA (Advanced Work Assignment), which factors are typically considered when assigning a case to an agent? Select the BEST answer.",opts:["Agent's age and seniority only","Agent availability, skill set, and current workload","Agent's location and language only","Case priority and category only"],ans:1,exp:"AWA considers multiple factors: agent availability (online/offline), skill set (matched to case requirements), current workload (capacity), channel, and case priority. It does not consider age or seniority directly."},
{id:12,domain:"Configuration",q:"A CSM property is set to control whether cases are automatically assigned or placed in a queue. Which configuration area contains this setting?",opts:["System Properties > CSM","Customer Service > Administration > Properties","ITSM > Assignment Rules","System > Notification"],ans:1,exp:"CSM system properties are managed under Customer Service > Administration > Properties. This is the central configuration hub for all CSM behaviors including assignment mode, channel settings, B2B/B2C model, and workspace settings."},
{id:13,domain:"Configuration",q:"What is the role of a Service Definition in CSM?",opts:["It defines the look and feel of the Customer Service Portal","It links a service offering to entitlement rules and case types","It configures the email channel for inbound case creation","It manages agent skill assignments for routing"],ans:1,exp:"A Service Definition describes the service being offered to a customer. It links the service to entitlement rules and specific Case Types. When a customer opens a case, the Service Definition auto-populates entitlement information."},
{id:14,domain:"Configuration",q:"In a CSM Playbook, what does a 'lane' define?",opts:["The SLA timer for each phase","Who is responsible for executing a specific step (agent, supervisor, or system)","The communication channel used in that step","The priority level of the playbook"],ans:1,exp:"In Process Automation Designer, lanes define the actor responsible for each step — it could be an agent, a supervisor, or an automated system. Leaving a lane unassigned is a common implementation mistake that causes playbooks to stall."},
{id:15,domain:"Configuration",q:"When configuring the CSM-ITSM Bridge, which Business Rule automatically updates the Case state when the linked Incident is closed?",opts:["Close Case on Incident Resolve","Update Case on Incident Closure","Sync Case Status from Incident","Cascade Incident Closure to Case"],ans:1,exp:"The Business Rule 'Update Case on Incident Closure' handles the reverse flow — when an Incident linked to a CSM Case is resolved/closed, this rule automatically updates the Case state. This specific rule name is tested on the exam."},
{id:16,domain:"Configuration",q:"An administrator wants to display customer-specific handling instructions to agents automatically when opening a case. Which feature should be configured?",opts:["Case Digest","Playbook Notes","Special Handling Notes","Agent Instructions Widget"],ans:2,exp:"Special Handling Notes are customer-specific instructions that appear automatically in the Agent Workspace when an agent works on a case for that specific customer (Account or Contact). Example: 'This is a VIP account — respond within 30 minutes.'"},
{id:17,domain:"Case Management",q:"Which case state allows the SLA timer to be paused because the delay is attributed to the customer?",opts:["New","Open","Awaiting Info","Resolved"],ans:2,exp:"The 'Awaiting Info' state can be configured with a Pause Condition on the SLA definition. When the case enters this state (waiting for customer input), the SLA timer pauses — the delay is the customer's responsibility, not the support team's."},
{id:18,domain:"Case Management",q:"What is a Case Digest in ServiceNow CSM?",opts:["A daily report of all open cases sent to managers","An automatic communication sent to all customers with cases linked to a Major Case","A summary of a case's activity timeline","A notification sent when a case SLA is breached"],ans:1,exp:"A Case Digest is an automatic communication mechanism tied to Major Issue Management. When a Major Case is created and individual customer cases are linked as children, a Case Digest can be sent to all affected customers with updates on the resolution progress."},
{id:19,domain:"Case Management",q:"What is the difference between Case Tasks and Case Activities?",opts:["They are the same thing with different names","Tasks are structured work items with their own state; Activities are timeline entries like notes and emails","Activities can be assigned; Tasks cannot","Tasks are created by customers; Activities are created by agents"],ans:1,exp:"Case Tasks are structured work items (sub-tasks) within a case with their own state, assignment, and due date. Activities are entries in the case timeline — notes, emails sent/received, state changes. They serve different purposes."},
{id:20,domain:"Case Management",q:"A major outage is affecting 500 customers. An implementer needs to send personalized bulk messages to specific subsets of impacted customers (e.g., only those with 'Gold' support). Which feature handles this?",opts:["Case Digest","Targeted Communications","Email Notification Rules","Bulk Case Update"],ans:1,exp:"Targeted Communications allow creating and sending personalized bulk messages to specific segments of customers, filterable by Account, product, case type, or support tier. Case Digest is for automatic updates on Major Case progress — Targeted Communications are for manual bulk messaging campaigns."},
{id:21,domain:"Case Management",q:"After a Case is set to 'Resolved', how many days does it typically auto-close if the customer does not respond?",opts:["2 days","5 days","7 days","30 days"],ans:1,exp:"By default, cases in the 'Resolved' state auto-close after 5 days if no customer response is received. This is configurable — the implementer can change the number of days in CSM Properties. The auto-close can also be disabled entirely."},
{id:22,domain:"Case Management",q:"Which CSM module allows cases to be escalated for on-site visits by field technicians?",opts:["IT Service Management","HR Service Delivery","Field Service Management (FSM)","Facilities Management"],ans:2,exp:"Field Service Management (FSM) handles on-site work orders and dispatching field technicians. CSM Cases can be escalated to FSM when physical presence is required for resolution. This integration is supported out-of-the-box."},
{id:23,domain:"Workspace & Analytics",q:"The Customer Service Portal in ServiceNow is built on which framework?",opts:["Next Experience (Polaris)","UI Builder","Service Portal (AngularJS)","Classic UI (GlideRecord)"],ans:2,exp:"The Customer Service Portal (CSP) is built on the Service Portal framework, which uses AngularJS. The Configurable Workspace/Agent Workspace uses the Next Experience framework. These are separate — do not confuse them on the exam."},
{id:24,domain:"Workspace & Analytics",q:"What is the purpose of the Engagement Messenger in CSM?",opts:["It sends automated case update emails to customers","It is an embeddable widget placed on external websites to let customers interact with support without leaving the site","It manages chat queues within the Agent Workspace","It notifies agents of new case assignments"],ans:1,exp:"Engagement Messenger is a lightweight widget that can be embedded on any external website (e.g., the company's product website). Customers can open cases, chat with agents, and get support without navigating to the ServiceNow portal."},
{id:25,domain:"Workspace & Analytics",q:"Which KPI measures the percentage of cases resolved on the very first customer contact?",opts:["CSAT","AHT","FCR (First Contact Resolution)","SLA Compliance Rate"],ans:2,exp:"FCR (First Contact Resolution) measures the percentage of cases resolved without requiring follow-up contacts. It is a key efficiency indicator. CSAT measures customer satisfaction. AHT is average handle time. SLA% measures adherence to service level targets."},
{id:26,domain:"Workspace & Analytics",q:"In Performance Analytics, what is a 'Scorecard'?",opts:["A report of all cases for a specific agent","An aggregation of KPI indicators for a single Account, showing the health of that customer relationship","A compliance report for regulatory purposes","A comparison of team performance metrics"],ans:1,exp:"A Scorecard in Performance Analytics aggregates multiple KPIs for a specific Account, giving management a comprehensive view of the health of that customer relationship. It answers questions like 'How are we performing for Acme Corp overall?'"},
{id:27,domain:"Workspace & Analytics",q:"An implementer needs to customize the columns visible in the Agent Workspace case list for the CSM team. Where is this configured?",opts:["System Properties","CSM Properties","UI Builder — Workspace configuration","List Editor in the classic interface"],ans:2,exp:"Workspace views, including list columns, filters, and sorting, are configured in UI Builder for the Configurable Workspace. This is the 2026 approach — not the classic List Editor. UI Builder provides a WYSIWYG interface for workspace customization."},
{id:28,domain:"Knowledge & BP",q:"According to KCS (Knowledge-Centered Support), when should knowledge be created?",opts:["Only by dedicated knowledge managers in advance","At the time it is used to solve a case, not pre-built in isolation","Only after a case is fully resolved and reviewed","Only by senior agents with special KCS certification"],ans:1,exp:"KCS principle: knowledge is created and improved AT THE TIME it is used to resolve a case. This means agents create articles as they solve problems, not in a separate pre-defined process. It ensures knowledge reflects real customer issues."},
{id:29,domain:"Knowledge & BP",q:"Which state must a knowledge article be in before customers can see it on the Customer Service Portal?",opts:["Draft","In Review","Published","Active"],ans:2,exp:"Only articles with status 'Published' are visible to customers on the CSP. The lifecycle is: Draft (created) → In Review (approval process) → Published (visible to customers) → Retired (no longer shown). Articles in Draft or In Review are only accessible internally."},
{id:30,domain:"Knowledge & BP",q:"What is the recommended sequence for a CSM implementation according to best practices?",opts:["Configure channels first → Define data model → Set up entitlements → Create case types","Define data model → Configure entitlements → Build case types → Configure channels","Build case types first → Configure entitlements → Define data model → Launch channels","Set up entitlements → Build case types → Define data model → Configure channels"],ans:1,exp:"Best practice sequence: 1) Define data model (B2B or B2C) first with the customer. 2) Configure entitlements (complex to retrofit). 3) Build case types linked to service definitions. 4) Configure and roll out channels gradually. This order prevents rework."},
{id:31,domain:"Configuration",q:"Which course in the Now Learning path for CIS-CSM must be completed as the foundational first step?",opts:["CSM Best Practices","CSM Implementation Workshop","Customer Service Management Essentials","ServiceNow Certified System Administrator"],ans:2,exp:"'Customer Service Management Essentials' (free, on-demand on Now Learning) is the required foundational course in the CIS-CSM learning path. It must be completed before the CSM Essentials Simulator and other advanced courses."},
{id:32,domain:"Configuration",q:"An agent sees a yellow banner with special instructions every time they open a case for a specific VIP account. What feature creates this banner?",opts:["Account Alert","Special Handling Notes","Agent Workspace Announcement","Priority Banner"],ans:1,exp:"Special Handling Notes are configured per Account (or Contact) and automatically display in the Agent Workspace when an agent opens a case for that customer. They provide context-specific instructions like 'VIP — escalate immediately if unresolved after 2 hours.'"},
{id:33,domain:"Data Model",q:"A Contact record is being created. Which field is REQUIRED in the B2B model?",opts:["Consumer","Install Base Item","Account","Contract"],ans:2,exp:"In the B2B model, a Contact must be linked to an Account. The Account field is required on the Contact record. This represents the company the person works for. This is a fundamental B2B data model constraint."},
{id:34,domain:"Case Management",q:"Which of the following is NOT a standard communication channel in ServiceNow CSM?",opts:["Email via Inbound Email Actions","Customer Service Portal","FTP File Transfer","Live Chat / Virtual Agent"],ans:2,exp:"FTP File Transfer is not a CSM communication channel. Standard channels include: Email (via Inbound Email Actions), Portal (Customer Service Portal), Chat/Virtual Agent, Phone/CTI, and Engagement Messenger. FTP is not customer service interaction channel."},
{id:35,domain:"Workspace & Analytics",q:"Which Performance Analytics feature allows breaking down a KPI metric by agent, group, category, or channel?",opts:["Scorecard","Breakdown","Dashboard","Trend Report"],ans:1,exp:"The Breakdown feature in Performance Analytics allows analyzing KPI metrics along multiple dimensions — by agent, group, category, channel, or time period. It answers 'Which team has the lowest FCR?' or 'Which channel generates the most volume?'"},
{id:36,domain:"Knowledge & BP",q:"An agent resolves a case and wants to create a new knowledge article documenting the solution. Where is the MOST efficient place to do this in CSM?",opts:["Navigate to Knowledge > Create Article separately","Use the knowledge article creation button directly in the case timeline","Submit a request to the knowledge manager","Export the case to Word and send to the knowledge team"],ans:1,exp:"KCS encourages agents to create knowledge directly from the case timeline. This is the most efficient approach — the case context (symptoms, resolution) is pre-populated into the article template. This is the KCS 'capture' step."},
{id:37,domain:"Data Model",q:"How does CSM support large enterprise customers with multiple regional subsidiaries?",opts:["Each subsidiary must be a separate ServiceNow instance","Account hierarchy — parent Account can have child Accounts","Only flat Account structures are supported","Create one Account with multiple Contacts for each subsidiary"],ans:1,exp:"ServiceNow CSM supports Account hierarchies — a parent Account (e.g., Acme Corp Global) can have child Accounts (e.g., Acme Corp Europe, Acme Corp Asia). Cases and entitlements can be associated at any level of the hierarchy."},
{id:38,domain:"Configuration",q:"A new CSM implementation for a telecom company needs to handle cases from email, portal, and phone simultaneously. What is the recommended rollout approach?",opts:["Launch all channels simultaneously on go-live day","Start with email and portal, then add phone/chat in subsequent phases","Start with phone only, then add digital channels","Configure all channels in dev, but only enable email in production initially"],ans:1,exp:"Best practice: Start with email and portal (lower complexity), then add phone/CTI and chat in subsequent phases. This reduces implementation risk, allows the team to learn and adjust, and prevents overwhelming agents with multiple new channels simultaneously."},
{id:39,domain:"Workspace & Analytics",q:"What does CSAT stand for in CSM analytics, and when is it typically measured?",opts:["Case Service Assessment Time — measured at case creation","Customer Satisfaction Score — measured via survey after case closure","Customer Service Availability Tracker — measured weekly","Case Status Audit Tool — measured during escalation"],ans:1,exp:"CSAT = Customer Satisfaction Score. It is measured via an automated survey sent to the customer after a case is closed (typically asking them to rate their experience on a 1-5 or 1-10 scale). It is a direct measure of customer perception of service quality."},
{id:40,domain:"Knowledge & BP",q:"The Now Create Methodology is required in the CIS-CSM learning path. What approach does it follow?",opts:["Waterfall project management","Agile (iterative sprint-based) methodology adapted for ServiceNow implementations","PRINCE2 project framework","Six Sigma DMAIC process"],ans:1,exp:"Now Create is ServiceNow's Agile implementation methodology. It uses iterative sprints, user stories, and stakeholder collaboration. The 'Get Started with the Now Create Methodology' course is a required free on-demand course in the CIS-CSM learning path."},
{id:121,domain:"Data Model",q:"Service-Aware Install Base (SAIB) extends the standard Install Base by doing which of the following?",opts:["Replacing the Sold Product table with a unified asset record","Associating Install Base Items with Service Definitions so the system can identify which services and customers are affected when a product fails","Automatically generating SLA definitions on each Install Base Item at creation","Synchronising Install Base Items with CMDB Configuration Items via Discovery"],ans:1,exp:"SAIB links Install Base Items to Service Definitions, creating a service-aware view of deployed products. When an IBI is flagged with an issue, SAIB identifies the services and customers impacted — enabling PCSO to generate proactive cases before customers call in. This is a key integration point between the D1 data model and proactive D3 case management."},
{id:122,domain:"Configuration",q:"An AWA queue is routing correctly, but some cases for customers with an Agent Affinity setting sit unassigned for hours even though agents are available. Which Affinity configuration MOST likely explains this?",opts:["No Affinity — the system cannot find an eligible agent","Soft Affinity — the preferred agent is absent and no fallback was configured","Hard Affinity — the case is held exclusively for the designated agent who is currently unavailable","Round-Robin Affinity — all agents have equal weight and the queue is balanced"],ans:2,exp:"Hard Affinity strictly reserves work for the designated agent regardless of their availability. If that agent is on leave, at capacity, or offline, the case waits rather than routing to another eligible agent. Soft Affinity would fall back to other agents. Hard Affinity is intentional but must be used knowingly to avoid silent queuing delays."},

// ── BLOCK 2 (Q41-80) ──
{id:41,domain:"Data Model",q:"In the CSM data model, which table stores customer Contact records?",opts:["sys_user","customer_account","customer_contact","csm_consumer"],ans:2,exp:"Contact records are stored in the 'customer_contact' table. This is different from sys_user (platform users) and consumer (B2C customers). Understanding CSM table names can appear in technical questions."},
{id:42,domain:"Configuration",q:"Which of the following BEST describes the difference between Assignment Rules and AWA in CSM?",opts:["They are identical features with different names","Assignment Rules are condition-based and assign to groups; AWA is capacity-aware and assigns to individual agents","AWA is only available with premium licenses","Assignment Rules work only for email channel; AWA works for all channels"],ans:1,exp:"Assignment Rules use conditions (if category=X, assign to Group Y) and typically assign to groups. AWA (Advanced Work Assignment) is more sophisticated — it considers agent availability, capacity, and skills to assign to a specific agent in real time."},
{id:43,domain:"Configuration",q:"A CSM Playbook has three phases: Diagnose, Escalate, Resolve. The Escalate phase should only trigger if the Diagnose phase determines it's a critical issue. Which PAD feature handles this conditional logic?",opts:["Playbook Stage","Conditional Activity","Lane Assignment","Phase Condition"],ans:3,exp:"In Process Automation Designer, Phase Conditions (or Conditions on stage transitions) control whether a phase is entered. A condition on the Escalate phase ensures it only activates if specific criteria (e.g., case flagged as critical in Diagnose) are met."},
{id:44,domain:"Data Model",q:"A customer calls support. The agent notices the customer has no active entitlement. The agent should:",opts:["Refuse to create the case","Create the case but document the entitlement violation","Acknowledge the warning and proceed — agents CAN still create the case","Transfer to a billing team only"],ans:2,exp:"Entitlement Verification shows a warning but does NOT block case creation. Agents can proceed at their discretion. The system records the entitlement status, and the business can decide how to handle it (bill separately, offer grace period, etc.)."},
{id:45,domain:"Case Management",q:"Which of the following actions does NOT automatically occur when a Major Case is resolved?",opts:["Child cases can be updated via Case Digest","Targeted Communications stop automatically","Resolution notes from Major Case can be propagated to child cases","Child cases are automatically closed without any action"],ans:3,exp:"When a Major Case is resolved, child cases are NOT automatically closed. They require separate closure actions. The implementer must configure whether and how the Major Case resolution triggers updates to child cases. This is often done via a Business Rule or Flow Designer."},
{id:46,domain:"Workspace & Analytics",q:"An implementer needs to display the Customer Service Portal in the customer's brand colors and logo. Where is this configured?",opts:["Service Portal > Portals > Theme","CSM Properties > Branding","System Properties > CSS","ITSM Portal Settings"],ans:0,exp:"Portal branding (logo, colors, header, theme) is configured in Service Portal > Portals > select the portal > Theme. This allows customizing the visual identity of the CSP to match the company's branding. Each portal can have a different theme."},
{id:47,domain:"Knowledge & BP",q:"What are Knowledge Blocks in ServiceNow CSM?",opts:["Sections of a knowledge article with predefined structure (Symptom, Cause, Resolution)","Blocked knowledge articles that are under review","Groups of related knowledge articles","Knowledge articles restricted to specific user groups"],ans:0,exp:"Knowledge Blocks are structured sections within knowledge articles — typically Symptom, Cause, and Resolution. They enforce consistency across articles and follow KCS best practices. Agents filling in these blocks ensure every article captures the problem, root cause, and fix."},
{id:48,domain:"Configuration",q:"Which CSM feature allows customers to interact with support directly from an external website without visiting the ServiceNow portal?",opts:["Virtual Agent","Customer Service Portal embedded mode","Engagement Messenger","Service Catalog External Access"],ans:2,exp:"Engagement Messenger is an embeddable JavaScript widget that companies add to their own website. Customers can open cases, chat with agents, and receive support without navigating away from the company's website. It connects to the ServiceNow backend seamlessly."},
{id:49,domain:"Configuration",q:"When configuring field mapping in the CSM-ITSM Bridge, which Case field typically maps to the Incident 'Urgency' field?",opts:["Category","Short Description","Priority","Severity"],ans:2,exp:"In the CSM-ITSM Bridge field mapping, Case Priority typically maps to Incident Urgency. This ensures the Incident is prioritized appropriately based on the customer case priority. Short Description also maps directly to Incident Short Description."},
{id:50,domain:"Case Management",q:"What is the purpose of a Case Task in ServiceNow CSM?",opts:["To record customer feedback on the case","To create a sub-activity within a case to track parallel workstreams","To link a case to a knowledge article","To document agent notes in the timeline"],ans:1,exp:"Case Tasks are structured sub-activities within a case. They have their own state (Open/Work in Progress/Closed), assignment, and due date. They are used to track parallel workstreams that need to be completed as part of resolving the case (e.g., 'Order replacement part', 'Get manager approval')."},
{id:51,domain:"Data Model",q:"An 'Install Base Item' in CSM directly represents which real-world concept?",opts:["A product in the product catalog","A specific instance of a product actively deployed at a customer site","A CMDB configuration item","A customer's purchase order"],ans:1,exp:"An Install Base Item represents a specific deployed instance of a product for a specific customer. Example: 'Customer Acme Corp has Model X Router (serial #12345) installed at their London office.' This is distinct from the Product Model (the generic product definition) and from a CMDB CI (though they can be linked)."},
{id:52,domain:"Configuration",q:"Which of these is a required course in the official Now Learning CIS-CSM learning path? (Select the MOST accurate answer)",opts:["CSM Implementation Workshop (ILT)","Customer Service Management Essentials (free on-demand)","Virtual Agent Advanced Implementation","CCaaS Integration Deep Dive"],ans:1,exp:"'Customer Service Management Essentials' is the free on-demand course required in the learning path. The CSM Implementation Workshop is recommended (3-day ILT) but not required. Virtual Agent and CCaaS are additional recommended courses."},
{id:53,domain:"Workspace & Analytics",q:"In the Agent Workspace, which panel shows related Account, Contact, and Asset information for the currently open case?",opts:["Activity Stream","Related Records tab","Contextual Side Panel","Knowledge Panel"],ans:2,exp:"Contextual Side Panels in the Agent Workspace automatically display relevant Account, Contact, Install Base, and Asset information for the case being worked. This gives agents full customer context without navigating away from the case."},
{id:54,domain:"Case Management",q:"A customer reopens a case that was previously closed. What typically happens to the SLA?",opts:["The original SLA continues from where it left off","SLA calculations reset when a case is reopened","The case gets a new, higher priority SLA automatically","SLA monitoring is suspended for reopened cases"],ans:1,exp:"When a case is reopened (moved from Closed back to Open or Awaiting Info), SLA calculations reset. The customer's renewed issue is treated as starting fresh from an SLA perspective. This ensures reopened cases are tracked accurately."},
{id:55,domain:"Data Model",q:"Which of the following is TRUE about the Consumer entity in the B2C model?",opts:["Consumer must always be linked to an Account","Consumer is a subtype of Contact","Consumer is a standalone entity with no parent Account","Consumer and Contact are interchangeable in all configurations"],ans:2,exp:"Consumer is completely standalone in the B2C model — it has no parent Account. This is the fundamental distinction from Contact (which MUST have a parent Account in B2B). Consumer has its own fields, form, and relationships suited for B2C scenarios."},
{id:56,domain:"Knowledge & BP",q:"What happens to a knowledge article's visibility when it is set to 'Retired' status?",opts:["It becomes read-only but still visible on the portal","It is permanently deleted","It is no longer shown on the Customer Service Portal","It requires re-approval to be published again"],ans:2,exp:"Retired knowledge articles are no longer displayed on the Customer Service Portal. They remain in the system for historical reference and audit purposes, but customers and agents using the portal search will not see them. They can be revived and republished if needed."},
{id:57,domain:"Configuration",q:"Skills-based routing in CSM ensures that:",opts:["Cases are routed based on the agent's seniority","Cases requiring specific technical knowledge are matched to agents with those skills","Cases are distributed equally regardless of skill","All cases go to the team lead first"],ans:1,exp:"Skills-based routing matches case requirements (e.g., 'needs Spanish speaker' or 'requires SAP expertise') to agents who have those skills registered in their profile. This improves First Contact Resolution by ensuring the right expert handles the case."},
{id:58,domain:"Workspace & Analytics",q:"Which of the following is NOT a standard CSM communication channel?",opts:["Email via Inbound Email Actions","Slack direct integration (native)","Phone/CTI via CCaaS","Engagement Messenger"],ans:1,exp:"Slack is not a native out-of-the-box CSM communication channel. The standard channels are: Email, Portal, Chat/Virtual Agent, Phone/CTI (CCaaS integration), and Engagement Messenger. Slack integration requires custom development or third-party connectors."},
{id:59,domain:"Case Management",q:"In Major Issue Management, what is the relationship between the Major Case and individual customer cases?",opts:["Major Case is a copy of each individual case","Individual cases are created FROM the Major Case","Individual customer cases are linked to the Major Case as child cases","Major Case and individual cases have no structural relationship"],ans:2,exp:"In Major Issue Management, individual customer cases are linked to the Major Case as CHILD CASES. The Major Case is the parent, and all affected customer cases are children. This hierarchy allows coordinated communication (Case Digest) and resolution tracking."},
{id:60,domain:"Knowledge & BP",q:"According to CSM best practices, what should be decided BEFORE configuring entitlements?",opts:["The number of agents in the support team","The B2B vs B2C data model selection","The branding colors for the portal","The Performance Analytics KPIs to track"],ans:1,exp:"The B2B vs B2C data model decision must be made FIRST — it fundamentally shapes everything else: entity relationships, entitlement structure, portal design, and case routing. Configuring entitlements before choosing the model leads to major rework."},
{id:61,domain:"Configuration",q:"What is the difference between a Case Type and a Service Definition in CSM?",opts:["They are synonymous — both define case behavior","Case Type defines case behavior and form; Service Definition links a service to entitlements and case types","Service Definition is for internal cases; Case Type is for customer-facing cases","Case Type is configured in ITSM; Service Definition is configured in CSM"],ans:1,exp:"Case Type defines how a case behaves: the form layout, workflow, SLA, and mandatory fields. Service Definition is the business-level description of a service offering, linked to entitlement rules and associated Case Types. Multiple Case Types can be associated with one Service Definition."},
{id:62,domain:"Data Model",q:"A company has acquired another company and wants to reflect the corporate hierarchy in ServiceNow CSM. Which feature supports this?",opts:["Contact Groups","Account Hierarchy (parent-child Account relationship)","Consumer Segments","Product Bundles"],ans:1,exp:"Account Hierarchy allows setting up parent-child relationships between Account records. The acquired company can be set as a child Account under the acquiring company's parent Account, reflecting the real-world corporate structure in CSM."},
{id:63,domain:"Case Management",q:"An agent wants to send a status update to all customers affected by a network outage. Which is the MOST appropriate CSM feature?",opts:["Send individual emails to each customer manually","Use Case Digest on the Major Case to automatically notify all linked customers","Use Performance Analytics dashboard","Create a knowledge article and hope customers find it"],ans:1,exp:"Case Digest on a Major Case is specifically designed for this scenario. It automatically identifies all customers with child cases linked to the Major Case and sends them a standardized update. This is far more efficient and reliable than manual individual emails."},
{id:64,domain:"Workspace & Analytics",q:"A CSM manager wants to see a single view of all KPIs for their top enterprise customer 'Globex Corp'. Which PA feature provides this?",opts:["Case List Filter","Account Scorecard","SLA Dashboard","KPI Breakdown by Category"],ans:1,exp:"An Account Scorecard aggregates all relevant KPIs for a specific Account, giving the manager a comprehensive view of performance for Globex Corp. It might show CSAT, SLA compliance, FCR, open case volume, and case aging for that specific customer."},
{id:65,domain:"Knowledge & BP",q:"Which structured article format does KCS recommend for support knowledge articles?",opts:["Problem-Impact-Solution","FAQ format with questions and answers","Symptom-Cause-Resolution (via Knowledge Blocks)","Executive Summary-Detail-Appendix"],ans:2,exp:"KCS recommends the Symptom-Cause-Resolution structure, implemented in ServiceNow via Knowledge Blocks. This format ensures each article captures: what the customer experienced (Symptom), why it happened (Cause), and how to fix it (Resolution). It makes articles actionable and searchable."},
{id:66,domain:"Configuration",q:"An implementer needs to prevent specific catalog items from being visible to all customers — only Gold tier customers should see them. Which mechanism controls this?",opts:["Portal theme settings","User criteria on catalog items linked to entitlement rules","CMDB access controls","Agent Workspace configuration"],ans:1,exp:"User Criteria on Service Catalog items, combined with entitlement rules, controls which customers can see which catalog items. You define criteria that checks for a valid Gold-tier entitlement — only customers meeting those criteria see the catalog item in the portal."},
{id:67,domain:"Data Model",q:"Which CSM entity would you use to record that 'Acme Corp has 100 units of Product X deployed across their offices'?",opts:["100 separate Contact records","Product Model with quantity 100","100 Install Base Items linked to Acme Corp","100 Asset records in ITSM"],ans:2,exp:"Each deployed unit would be an Install Base Item linked to the Acme Corp Account and the Product X Product Model. 100 units = 100 Install Base Items. This allows tracking each unit individually (serial number, location, status) for support and case management purposes."},
{id:68,domain:"Case Management",q:"What is the purpose of Inbound Email Actions in CSM?",opts:["To send SLA breach notifications to customers","To automatically create or update cases from incoming customer emails","To route emails between agent teams","To generate email reports of open cases"],ans:1,exp:"Inbound Email Actions define rules for processing incoming emails. When a customer emails the support address, the Inbound Email Action can automatically create a new Case (with the email body as the description), update an existing case (if a case number is in the subject), or route the email to specific queues."},
{id:69,domain:"Workspace & Analytics",q:"How are Performance Analytics indicators different from standard ServiceNow reports?",opts:["PA indicators are real-time and trend over time; standard reports are static snapshots","PA indicators can only be used for cases; reports work for all tables","Standard reports are faster; PA indicators are slower to load","They are identical — PA is just a newer name for reporting"],ans:0,exp:"Performance Analytics indicators are calculated over time and support trending, targets, and breakdowns — they are designed for operational management. Standard Reports are static snapshots of current data. PA provides historical trend analysis and KPI management that basic reports cannot."},
{id:70,domain:"Knowledge & BP",q:"An organization wants to automatically retire knowledge articles that have been rated below 2 stars by 10+ users. What feature enables this?",opts:["Knowledge Feedback with auto-retirement rules","Knowledge Lifecycle Manager","Article Quality Score automation","SLA-based article expiration"],ans:0,exp:"Knowledge Feedback mechanisms in ServiceNow can be configured to automatically trigger article retirement workflows when quality thresholds are breached (low ratings, no views, etc.). This automates knowledge base hygiene without requiring manual review of every article."},
{id:71,domain:"Configuration",q:"In CSM, 'Communities' (available in the professional suite) serves what purpose?",opts:["Internal agent collaboration only","Customer-facing forums where customers can help each other and find answers","Executive stakeholder reporting","ITSM change management discussions"],ans:1,exp:"Communities in CSM creates customer-facing forums where customers can post questions, share solutions, and collaborate. It reduces case volume by enabling peer-to-peer support. It's part of the CSM Professional Suite and is an additional recommended course in the learning path."},
{id:72,domain:"Data Model",q:"An entitlement automatically checks whether a customer has the right to support when a case is opened. What is this process called?",opts:["Entitlement Assignment","Entitlement Verification","SLA Calculation","Contract Validation"],ans:1,exp:"Entitlement Verification is the automatic process that runs when a case is created to check if the customer (Account/Contact/Consumer) has a valid active entitlement. It displays a verification indicator on the case and can warn agents if no entitlement is found."},
{id:73,domain:"Configuration",q:"Which of the following accurately describes how AWA handles agent capacity?",opts:["AWA assigns cases until the agent logs out, regardless of workload","AWA respects capacity thresholds — agents are not assigned new work when at maximum capacity","AWA only considers online/offline status, not workload","AWA assigns based on last-in-first-out queue order"],ans:1,exp:"AWA manages agent capacity — each agent can have a maximum concurrent case limit defined. When an agent reaches capacity, AWA stops assigning new cases to them and routes new work to other available agents. This prevents agent overload and improves service quality."},
{id:74,domain:"Case Management",q:"A customer emails the support address with subject 'RE: CASE0001234 still not resolved'. The system should update the existing case. Which feature handles this?",opts:["Inbound Email Action with case reference matching","Assignment Rule based on subject","Business Rule on email receipt","Virtual Agent email processor"],ans:0,exp:"Inbound Email Actions can be configured to recognize case numbers in email subjects (RE: CASE0001234) and automatically update the existing case rather than creating a new one. This is a standard Inbound Email Action configuration that recognizes the case reference pattern."},
{id:75,domain:"Workspace & Analytics",q:"A company wants to offer customers a way to request support directly from their product's mobile app. Which CSM feature is MOST appropriate?",opts:["Service Portal embedded in an iframe","Engagement Messenger SDK/API integration","CSP external user login","Email-only channel"],ans:1,exp:"Engagement Messenger provides an SDK/API that allows integration with external applications including mobile apps. This enables customers to access support, open cases, and chat with agents directly within the company's own app without launching a browser."},
{id:76,domain:"Knowledge & BP",q:"According to ServiceNow best practices, knowledge article quality is improved primarily by:",opts:["Having a dedicated team rewrite all articles annually","Agents updating articles in real-time as they resolve cases (KCS approach)","Hiring external technical writers","Locking articles so only managers can edit them"],ans:1,exp:"KCS (Knowledge-Centered Support) holds that quality improves when agents update articles as they solve cases — capturing real customer issues and effective resolutions. Annual rewrites by a separate team miss the continuous improvement that comes from agents working with knowledge daily."},
{id:77,domain:"Configuration",q:"After a CSM implementation go-live, agents report that the Playbook is not activating automatically when cases reach the 'In Progress' state. What is the MOST likely cause?",opts:["Playbooks require manual activation only","The Playbook trigger condition is not configured to match the 'In Progress' state","The CSM license doesn't include Playbooks","Agents need special permission to view Playbooks"],ans:1,exp:"Playbooks have configurable trigger conditions. If the trigger is not set to activate on 'In Progress' state transition, the Playbook won't auto-launch. The implementer needs to verify the Trigger Configuration in Process Automation Designer and ensure the condition matches the case state change."},
{id:78,domain:"Data Model",q:"Which of the following best describes the relationship between Contracts and Entitlements in CSM?",opts:["They are the same thing","A Contract can have multiple Entitlements; Entitlements derive their validity from the Contract","An Entitlement always creates a Contract automatically","Contracts are for B2B only; Entitlements are for B2C only"],ans:1,exp:"A Contract defines the formal agreement between the company and a customer Account (duration, terms). An Entitlement is derived from the Contract and defines the specific support rights (service level, case limits, hours). One Contract can have multiple Entitlements for different services."},
{id:79,domain:"Case Management",q:"In CSM, which state indicates that a case has been transferred to Field Service Management for an on-site visit?",opts:["Escalated","Awaiting Field Service","In Progress — Field","Dispatched"],ans:0,exp:"When a Case is escalated to FSM, the case state often reflects 'Escalated' or a custom state configured by the implementer. The exact state name can vary by implementation. The key exam concept is that Cases CAN be escalated to FSM for on-site resolution, and the integration is supported out-of-the-box."},
{id:80,domain:"Knowledge & BP",q:"The 'CSM Best Practices' course in Now Learning covers which primary topics?",opts:["Only database optimization techniques","Implementation patterns, anti-patterns, governance, and operational best practices for CSM","Advanced scripting for CSM customization","CCaaS integration technical details"],ans:1,exp:"The 'CSM Best Practices' free on-demand course covers implementation patterns (what works), anti-patterns (what to avoid), governance models, and operational best practices for running CSM effectively. It's a recommended course in the CIS-CSM learning path."},
{id:123,domain:"Configuration",q:"An implementer is setting up Proactive Customer Service Operations (PCSO). A major cloud storage outage is detected by ITOM. Which PCSO record serves as the central anchor for generating proactive cases and coordinating customer notifications?",opts:["Major Case record — created directly from the ITOM alert","Outage Record — captures the disruption event and drives proactive case creation and Targeted Communications","Change Request linked to the outage CI","A standard Problem record promoted to customer-facing status"],ans:1,exp:"In PCSO, the Outage Record is the central object for a service disruption event. It links to the ITOM source event, identifies affected products/services, and orchestrates automated proactive case creation for affected customers and Targeted Communications campaigns. This enables the support team to act before a surge of inbound contacts."},
{id:124,domain:"Case Management",q:"An agent managing a high-priority case sees a RED Action Status Indicator on an adjacent case in their Agent Workspace list. Without opening it, what does the red indicator communicate?",opts:["The case has an unread customer reply waiting for the agent","The case SLA is breached or at immediate risk and requires agent attention","The case has been escalated by a senior manager","A knowledge article linked to the case has been retired and needs replacement"],ans:1,exp:"Red Action Status Indicators in the Agent Workspace case list flag cases requiring immediate attention — typically due to an SLA breach, an overdue follow-up, or a configured urgent trigger condition. A blue dot signals unread customer activity. This colour coding lets agents triage their entire queue at a glance without opening each record individually."},

// ── BLOCK 3 (Q81-120) ──
{id:81,domain:"Configuration",q:"A company wants to use Now Assist for CSM to help agents summarize long case histories. This requires which license tier?",opts:["Base CSM license","CSM Professional Suite","CSM Professional Plus Suite","No additional license — it's included by default"],ans:2,exp:"Now Assist features (including Case Summarization, Suggested Resolutions, Chat Assist) are part of the CSM Professional Plus Suite. They require an additional license beyond the base CIS-CSM application. The learning path includes a 'Now Assist for CSM' free course for awareness."},
{id:82,domain:"Data Model",q:"Which of the following is a correct statement about Account Hierarchy in CSM?",opts:["Account hierarchies are limited to 2 levels (parent and child)","Account hierarchies can have unlimited levels and cases can be linked at any level","Account hierarchies are only for display purposes — they do not affect case routing","Account hierarchies require custom configuration and are not available OOTB"],ans:1,exp:"ServiceNow CSM supports multi-level Account hierarchies with no fixed depth limit. Cases, entitlements, and contacts can be associated at any level in the hierarchy. This is available out-of-the-box (OOTB) and is essential for multinational enterprise customers."},
{id:83,domain:"Configuration",q:"A CSM implementer wants to create a playbook where Step 3 should only execute if Step 2 output indicates 'hardware defect'. Where is this conditional flow defined in PAD?",opts:["Assignment Rules on the step","Stage Transition Condition on the connection between steps","Script Include attached to the step","Flow Designer subflow"],ans:1,exp:"In Process Automation Designer (PAD), Stage Transition Conditions are placed on the connections/transitions between phases or activities. They define when the flow proceeds to the next step based on data conditions — perfect for 'only proceed to hardware repair step if defect is confirmed'."},
{id:84,domain:"Case Management",q:"Which CSM feature automatically sends periodic status updates to all customers affected by an ongoing Major Issue?",opts:["Targeted Communications","Scheduled Reports","Case Digest","SLA Notifications"],ans:2,exp:"Case Digest is specifically designed for ongoing Major Issues. It can be configured to send periodic (e.g., every 2 hours, or on demand) status updates to all customers who have cases linked to the Major Case. This keeps impacted customers informed without agents manually emailing each one."},
{id:85,domain:"Workspace & Analytics",q:"An agent is working a case and needs to find similar resolved cases to accelerate resolution. Which workspace feature helps most?",opts:["Related Cases tab showing similar incidents","Contextual Search / Knowledge panel in the workspace","SLA timer panel","Entitlement verification banner"],ans:1,exp:"The Contextual Knowledge panel in the Agent Workspace surfaces relevant knowledge articles and similar past cases based on the current case's content (category, short description, keywords). This helps agents find proven resolutions quickly without leaving the workspace."},
{id:86,domain:"Knowledge & BP",q:"An article has been Published in CSM. A customer leaves a 1-star rating with comment 'This solution did not work for me'. What can the system automatically trigger?",opts:["Immediate deletion of the article","A retirement workflow to review the article's validity","A case creation for the customer's complaint","An escalation to the original article author"],ans:1,exp:"Negative feedback (low ratings) can trigger automated Knowledge Feedback workflows — a review or retirement process for the article. The article goes back to In Review state where knowledge managers can update or retire it. This is a core KCS quality improvement mechanism."},
{id:87,domain:"Configuration",q:"The CSM Agent Workspace is configured using which ServiceNow tool?",opts:["Classic UI form editor","Workflow Editor","UI Builder","Studio IDE"],ans:2,exp:"The Configurable Workspace for CSM agents is customized using UI Builder. This tool allows configuring workspace views, list columns, form layouts, side panels, and other workspace elements in a no-code/low-code visual environment."},
{id:88,domain:"Data Model",q:"A company sells software subscriptions. They want to track that Customer A has Version 2.1 running, and Customer B has Version 3.0. Which CSM objects model this?",opts:["Two separate CMDB CIs","Two Install Base Items, each linked to a different Product Model version","Two Contracts with different service levels","Two Service Definitions with version conditions"],ans:1,exp:"Two Install Base Items — one for Customer A linked to Product Model 'Software v2.1', one for Customer B linked to Product Model 'Software v3.0'. Install Base Items track the specific version deployed per customer, enabling version-specific support and case tracking."},
{id:89,domain:"Case Management",q:"In which order do Inbound Email Actions process rules when multiple rules match an incoming email?",opts:["Alphabetical by name","By created date, oldest first","By Order field (lowest number = highest priority, processed first)","Randomly — all matching rules execute in parallel"],ans:2,exp:"Inbound Email Actions use an Order field to determine processing sequence. The rule with the lowest Order number is evaluated first. The first matching rule wins and executes — subsequent rules are not evaluated unless the first rule is configured to 'continue processing'."},
{id:90,domain:"Workspace & Analytics",q:"A CSM manager wants a dashboard that shows CSAT trends over the last 6 months broken down by support region. Which combination of PA features is needed?",opts:["Standard Report + List Filter","PA Indicator (CSAT) + Breakdown (by region) + Trend visualization","Simple chart with filter","Exported Excel report with pivot table"],ans:1,exp:"This requires: a PA Indicator (CSAT score), a Breakdown dimension (by region), and a Trend view (6-month history). Performance Analytics is purpose-built for this — standard reports cannot easily provide trending + breakdown + live KPI tracking simultaneously."},
{id:91,domain:"Knowledge & BP",q:"What is the 'CSM Implementation Workshop' in the Now Learning path?",opts:["A required free on-demand course","An optional 3-day instructor-led training (ILT) recommended before the exam","A practice sandbox environment","The official exam itself"],ans:1,exp:"The CSM Implementation Workshop is a 3-day instructor-led training (ILT) that is RECOMMENDED (not required) as practical hands-on preparation. It costs learning credits and is positioned as pre-exam practice. It is distinct from the required free online courses."},
{id:92,domain:"Configuration",q:"What is the maximum number of Case Types that can be associated with a single Service Definition?",opts:["Only one","Two (primary and secondary)","As many as needed — no hard limit","Three"],ans:2,exp:"There is no hard limit on the number of Case Types associated with a Service Definition. A single Service Definition can have multiple Case Types, each representing a different category of issue (e.g., Billing Issue, Technical Issue, Delivery Issue) all under the same service."},
{id:93,domain:"Data Model",q:"Which field on a Case record indicates that Entitlement Verification has confirmed the customer has valid support rights?",opts:["Entitlement Status = Active","Entitlement Verified = true / green indicator","Contract Status = Valid","SLA = Applied"],ans:1,exp:"When Entitlement Verification succeeds, the Case shows an 'Entitlement Verified' indicator (typically a green checkmark or a field set to true). This confirms the customer has valid active entitlement for the service being requested."},
{id:94,domain:"Case Management",q:"An SLA on a case is configured with a pause condition for 'Awaiting Info' state. The case has been in Awaiting Info for 3 days. What does the SLA timer show?",opts:["The full 3 days counted against the SLA","The SLA timer is paused — those 3 days do NOT count against the SLA target","The case is automatically escalated after 24 hours in Awaiting Info","The SLA is voided after 48 hours in Awaiting Info"],ans:1,exp:"With a Pause Condition active, the SLA timer stops counting while the case is in 'Awaiting Info'. Those 3 days are not charged to the SLA. The timer resumes when the case moves out of Awaiting Info (e.g., when the customer provides the requested information)."},
{id:95,domain:"Workspace & Analytics",q:"A customer uses the Customer Service Portal to update their case with new information. In the Agent Workspace, where does this update appear?",opts:["Separate inbox for customer updates","Case Activity Stream / Timeline","SLA breach notification","Assignment Rule trigger"],ans:1,exp:"Customer updates via the portal (notes, attachments, replies) appear in the Case Activity Stream (Timeline) in the Agent Workspace. The agent sees a chronological history of all interactions including customer portal updates, emails sent/received, and state changes."},
{id:96,domain:"Knowledge & BP",q:"How does 'Now Assist for CSM' improve agent productivity? (Select the BEST answer)",opts:["It automatically closes cases without agent review","It generates case summaries, suggests resolutions, and provides chat response suggestions using generative AI","It replaces agents entirely for Tier 1 support","It only helps with knowledge article searching"],ans:1,exp:"Now Assist for CSM uses generative AI to: 1) Summarize long case histories for agents picking up existing cases, 2) Suggest resolution steps based on similar cases and knowledge, 3) Provide response suggestions during chat interactions. It augments agents — it does not replace them."},
{id:97,domain:"Configuration",q:"A CSM system has multiple Assignment Rules. Rule 1 assigns 'Network Issues' to Group A. Rule 2 assigns 'Priority 1 cases' to Group B. A P1 Network Issue case is created. Which group gets it?",opts:["Group A (Rule 1 matches first alphabetically)","Group B (Rule 2 matches — last rule wins)","The group assigned by the rule with the LOWER order number (higher priority)","Both groups receive notification"],ans:2,exp:"Assignment Rules process in Order number sequence — the rule with the lowest Order number (highest priority) that matches wins. If Rule 1 has Order 100 and Rule 2 has Order 50, Rule 2 (Group B) fires. The implementation must carefully set rule order to handle overlapping conditions correctly."},
{id:98,domain:"Data Model",q:"In a B2C implementation for a utility company, a customer 'Luigi Bianchi' calls about a billing error. Which CSM entity is the primary record?",opts:["Account: Luigi Bianchi","Contact: Luigi Bianchi linked to a personal Account","Consumer: Luigi Bianchi (standalone)","User: luigi.bianchi@email.com"],ans:2,exp:"In B2C, the primary entity is Consumer — a standalone record for Luigi Bianchi without any parent Account. The Case is linked directly to the Consumer. The sys_user (User) record is for ServiceNow platform login, not for CSM customer identity."},
{id:99,domain:"Case Management",q:"A CSM implementer is asked to ensure cases from 'Gold' tier customers are never stuck in queue for more than 15 minutes before agent assignment. Which configuration achieves this?",opts:["Set a 15-minute case expiry","Configure an SLA with a 15-minute Response Time for Gold entitlements, with escalation notification at 10 minutes","Create a Business Rule to auto-close cases after 15 minutes","Use Performance Analytics to track it retrospectively only"],ans:1,exp:"Configuring an SLA with a 15-minute Response Time target (tied to Gold entitlement) with a warning escalation notification at 10 minutes (before breach) is the correct approach. The SLA proactively alerts supervisors when a Gold case is at risk, enabling action before the 15-minute target is missed."},
{id:100,domain:"Workspace & Analytics",q:"What distinguishes the 'Configurable Workspace' from the classic CSM case form?",opts:["Configurable Workspace has less functionality","Configurable Workspace provides contextual panels, real-time data, omnichannel interactions in a single view — customizable via UI Builder","Classic form is better for high-volume environments","They are identical — just different visual themes"],ans:1,exp:"The Configurable Workspace is fundamentally different: it integrates contextual side panels (account info, related cases, knowledge), omnichannel interactions, timeline, and real-time data in a single unified view. It is fully customizable via UI Builder. The classic form is a standard ServiceNow form with limited contextual capabilities."},
{id:101,domain:"Configuration",q:"An implementation team is building a CSM solution. They're debating whether to set up routing BEFORE or AFTER defining case types. What does best practice recommend?",opts:["Routing (Assignment Rules) should be configured first","Case Types should be defined first — routing rules often reference case type fields","They should be configured simultaneously","Routing doesn't depend on case types at all"],ans:1,exp:"Best practice: Define Case Types first. Assignment Rules frequently reference case type fields (e.g., assign 'Hardware Failure' case type to specific group). Building routing before case types means either using generic rules initially or doing rework later. Case Types define the categories that routing rules act on."},
{id:102,domain:"Data Model",q:"Which of the following statements about Contracts in CSM is CORRECT?",opts:["Contracts are optional and never affect entitlement processing","Contracts define formal agreements and are the source from which Entitlements derive their validity periods","Contracts automatically create cases when they expire","Contracts are only used in B2C implementations"],ans:1,exp:"Contracts define formal agreements between the company and customer (duration, terms, auto-renewal). Entitlements are derived from Contracts — the entitlement inherits its validity period from the contract. When a contract expires, associated entitlements also expire, affecting support rights."},
{id:103,domain:"Case Management",q:"An implementer needs to track that an agent called a customer, left a voicemail, and then emailed follow-up details. All within the same case. Where are these interactions recorded?",opts:["Three separate Cases are created","In the Case Activity Stream (Timeline)","In the Assignment Rules log","In a separate Communication Log table"],ans:1,exp:"All interactions within a case are recorded in the Activity Stream / Timeline — the chronological log of everything that happened on the case. Phone calls, emails, notes, state changes, and customer portal updates all appear here, providing a complete interaction history."},
{id:104,domain:"Workspace & Analytics",q:"A CSM portal shows a customer their open cases, a knowledge article search bar, and a service request catalog. Which three CSM components are being used?",opts:["Case Module, Knowledge Module, and ITSM Service Catalog","CSP with My Cases widget, Knowledge Articles widget, and Service Catalog widget","Three separate portals combined","ITSM Employee Service Center with CSM extension"],ans:1,exp:"This is the Customer Service Portal (CSP) configured with: My Cases widget (open cases list), Knowledge Articles widget (search), and Service Catalog widget (service requests). These are standard CSM portal widgets assembled in the Service Portal framework."},
{id:105,domain:"Knowledge & BP",q:"A knowledge manager notices that 80% of knowledge articles have never been viewed. According to KCS, what should happen to these articles?",opts:["They should be printed and distributed to agents","They should be reviewed and likely retired — unviewed articles are not helping anyone","They should be promoted on the portal homepage","They should be auto-converted to FAQs"],ans:1,exp:"KCS emphasizes knowledge quality over quantity. Unviewed articles are not delivering value. Per best practices, they should be reviewed: if they address real issues but aren't findable, improve searchability. If they address no real issues, retire them. A massive unused knowledge base is a maintenance burden."},
{id:106,domain:"Configuration",q:"Which of these items would you configure in 'UI Builder' (as opposed to Classic Service Portal configuration)?",opts:["Service Portal theme colors","CSM Agent Workspace layout and side panels","Knowledge Base categories","Email notification templates"],ans:1,exp:"UI Builder is used to configure the Configurable Workspace (Agent Workspace) — including layout, side panel content, workspace views, and lists. Service Portal themes are in the Service Portal admin. Knowledge Base categories are in Knowledge Management. Email templates are in Notifications."},
{id:107,domain:"Data Model",q:"A customer has purchased three different products from a vendor. Each product has its own support terms. How many Entitlements would typically be created?",opts:["One consolidated Entitlement for all products","One Entitlement per product purchased (three Entitlements)","One Contract with no Entitlements","Entitlements are only per Account, not per product"],ans:1,exp:"Typically, one Product Entitlement per product purchased — each product may have different support terms, response times, and service levels. Three products = three Entitlements, all potentially linked to one Master Contract. This granularity allows entitlement verification to match the specific product in the case."},
{id:108,domain:"Case Management",q:"What is the PRIMARY benefit of linking Case Tasks to a Case (rather than handling everything in the case timeline)?",opts:["Tasks are easier to delete","Tasks can be assigned to different teams/individuals and tracked separately from the main case","Tasks are cheaper in licensing","Tasks bypass SLA calculations"],ans:1,exp:"Case Tasks can be assigned to different teams, individuals, or external resources and tracked independently with their own states and due dates. This is critical for complex cases that require parallel workstreams — e.g., one team orders a part while another does remote diagnostics, both linked to the same parent case."},
{id:109,domain:"Workspace & Analytics",q:"In Performance Analytics for CSM, what is the difference between a 'Target' and a 'Threshold'?",opts:["They are identical — just different terminology","A Target is the goal value; a Threshold triggers a color change or alert when the indicator approaches/exceeds a limit","A Target is set by management; a Threshold is auto-calculated","Targets are for CSAT; Thresholds are for SLA only"],ans:1,exp:"In PA: Target = the goal you want to achieve (e.g., CSAT ≥ 4.5). Threshold = a boundary that changes the indicator's visual status (typically amber warning / red critical). Thresholds create visual alerts when performance deteriorates. Targets define success."},
{id:110,domain:"Knowledge & BP",q:"A CSM implementation team wants to ensure that all new cases for 'Password Reset' issues are automatically linked to the relevant knowledge article. Which feature enables this?",opts:["Entitlement auto-match","Suggested Knowledge Articles configured via PA","Predictive Intelligence — topic recommendations based on case content","Assignment Rules with knowledge linking"],ans:2,exp:"Predictive Intelligence (available in CSM, and a Micro-Certification in the professional suite path) can automatically suggest and link knowledge articles based on case content analysis. When a 'Password Reset' case is created, PI identifies the relevant article. This is a Now Intelligence feature integrated with CSM."},
{id:111,domain:"Configuration",q:"An implementer is told that the company's SLA for VIP customers states: 'We will respond within 1 hour, and resolve within 8 business hours.' How many SLA definitions are needed?",opts:["One combined SLA with multiple conditions","Two separate SLA definitions: one for Response Time (1 hour) and one for Resolution Time (8 business hours)","Four SLAs — one per business hour block","Only the resolution SLA matters; response is tracked differently"],ans:1,exp:"Best practice: separate SLA definitions for Response Time (first agent touch) and Resolution Time (case closure). Two SLAs are created and both linked to the VIP entitlement. This allows the system to track and report on both metrics independently."},
{id:112,domain:"Data Model",q:"What is the 'customer_account' table used for in ServiceNow?",opts:["Storing financial account numbers","Storing the customer company (Account) records in the B2B CSM model","Storing all ServiceNow user accounts","Storing billing information for contracts"],ans:1,exp:"The 'customer_account' table stores Account records — the company-level entities in the CSM B2B model. Each row represents a customer company. This is distinct from sys_user (platform users), sys_account (internal ServiceNow account), and financial/billing tables."},
{id:113,domain:"Case Management",q:"In CSM, when is it appropriate to use Targeted Communications instead of Case Digest?",opts:["When you want an automated update on Major Case progress","When you want to proactively reach out to specific customer segments with custom messaging about an issue or announcement","When SLAs are breached","When closing cases in bulk"],ans:1,exp:"Targeted Communications is for proactive, custom messaging to defined customer segments. Example: notify all customers who purchased Product X that an upgrade is available. Case Digest is specifically for updating customers on Major Case resolution progress. They serve different communication needs."},
{id:114,domain:"Workspace & Analytics",q:"A new CSM agent asks: 'Where do I find instructions specific to the customer I'm about to call?' The answer is:",opts:["Check the Knowledge Base","Look at the Account record in Classic UI","Check the Special Handling Notes displayed in the Agent Workspace when the case is open","Review the SLA timer"],ans:2,exp:"Special Handling Notes appear automatically in the Agent Workspace when the agent opens a case for a customer that has handling notes configured. The agent doesn't need to navigate anywhere — the notes appear contextually, ensuring the agent sees critical instructions before interacting with the customer."},
{id:115,domain:"Knowledge & BP",q:"According to the Now Create Methodology, what is a 'User Story' in a CSM implementation?",opts:["A description of how a customer uses the portal","A short description of a feature from the end-user's perspective (As a [role], I want [capability] so that [benefit])","The narrative in a knowledge article","A case description template"],ans:1,exp:"In Now Create (Agile), User Stories follow the format: 'As a [customer/agent/manager], I want [functionality] so that [business value].' They define requirements from the end-user perspective and are used in sprint planning. Example: 'As a CSM agent, I want to see all open cases for an Account in one view so I can provide context-aware support.'"},
{id:116,domain:"Configuration",q:"What happens when an Assignment Rule matches a case but the target group has no available agents?",opts:["The case is returned to the unassigned queue","The case is assigned to the group (not a specific agent) and appears in the group's queue for manual pickup","The case is escalated to the next priority group automatically","Assignment fails and the case remains unassigned indefinitely"],ans:1,exp:"Assignment Rules assign to a Group — not necessarily a specific agent. When the group has no immediately available agent, the case appears in the group's queue. Agents in that group see the queued case and pick it up when available. AWA can then further assign to a specific agent if configured."},
{id:117,domain:"Data Model",q:"A company offers 'Platinum Support' that includes: unlimited cases, 24/7 access, and 1-hour response SLA. Which entitlement type BEST covers the 'unlimited cases' aspect?",opts:["Time-Based Entitlement","Service Entitlement","Allocated Entitlement with limit 9999","No entitlement needed — unlimited cases require no entitlement tracking"],ans:1,exp:"Service Entitlement covers a service level (24/7 access, 1-hour SLA) without case limits. The 'unlimited cases' aspect means there's no Allocated Entitlement constraint. A Service Entitlement tied to the Platinum Support contract captures the service level and validity period without a case cap."},
{id:118,domain:"Case Management",q:"An agent is resolving a CSM case and notices the customer has 3 other open cases. Where in the Agent Workspace can the agent quickly see these related cases?",opts:["They must open a separate browser tab to search","In the Contextual Side Panel or Related Records section of the workspace","In the SLA timer panel","In the Knowledge Articles panel"],ans:1,exp:"The Agent Workspace's Contextual Side Panel shows related information for the current customer — including other open cases for that Account or Contact. This contextual awareness lets agents understand the customer's full situation without navigating away."},
{id:119,domain:"Knowledge & BP",q:"What is the recommended maximum age for a 'Current' knowledge article in a CSM knowledge base before it should be reviewed for accuracy?",opts:["6 months","1 year","2 years","ServiceNow does not prescribe a specific age — review triggers are based on feedback and usage metrics"],ans:3,exp:"KCS and ServiceNow best practices recommend review triggers based on signals: low ratings, declining views, high customer feedback volume, and product version changes. There's no hard prescribed maximum age. Usage signals and feedback are better indicators of when review is needed than arbitrary time periods."},
{id:120,domain:"Configuration",q:"Which of the following is NOT part of the standard CIS-CSM exam scope for 2026?",opts:["Configuring CSM Playbooks using PAD","Setting up the CSM-ITSM Bridge","Advanced REST API scripting for CSM integrations","Configuring Case Routing with Assignment Rules"],ans:2,exp:"Advanced REST API scripting is not in the standard CIS-CSM exam scope. The exam focuses on configuration (not custom scripting), including Playbooks, CSM-ITSM Bridge, case routing, entitlements, workspace, portals, and knowledge management. Deep scripting knowledge is more relevant to the CAD (Certified Application Developer) exam."},
{id:125,domain:"Case Management",q:"A customer contacts support about three separate product issues in a single call. Rather than opening three separate cases, which CSM feature allows the agent to capture each issue as a structured item within a single Case record?",opts:["Case Tasks — one task per product issue","Case Lines — individual line items per product or issue within one Case","Case Merge — pre-merging anticipated duplicates before creation","Major Case child links — linking all three issues as children of a parent"],ans:1,exp:"Case Lines allow a single Case to contain multiple structured line items, each representing a distinct product, service, or issue. Each line is tracked and resolved individually while keeping the full customer interaction consolidated on one record. This avoids case proliferation and gives agents a clean, unified view of multi-product contacts."},
{id:126,domain:"Case Management",q:"Which of the following BEST describes the difference between Action Status Indicators and SLA timers in the Agent Workspace?",opts:["They are the same — Action Status Indicators display the SLA countdown","Action Status Indicators show real-time customer activity signals (unread reply = blue, urgent action needed = red); SLA timers show elapsed/remaining time against the defined target","Action Status Indicators are only visible to supervisors; SLA timers are agent-facing","SLA timers replace Action Status Indicators when the 90-minute exam timer is active"],ans:1,exp:"Action Status Indicators (coloured dots) communicate customer activity and urgency signals at a glance on the case list — they are not SLA timers. SLA timers are separate components showing elapsed time and countdown to breach. Both are visible in the Agent Workspace but serve distinct purposes: one signals what needs attention now, the other tracks contractual time targets."}
];

